-- 清空旧的学校相关数据
DELETE FROM research_projects;
DELETE FROM professors;
DELETE FROM universities;
DELETE FROM project_matches;

-- 显示清空后的记录数
SELECT 'universities' as table_name, COUNT(*) as count FROM universities
UNION ALL
SELECT 'professors', COUNT(*) FROM professors
UNION ALL
SELECT 'research_projects', COUNT(*) FROM research_projects
UNION ALL
SELECT 'project_matches', COUNT(*) FROM project_matches;

